text:
a {
  color: var(--adm-color-primary);
  transition: opacity ease-in-out 0.2s;
  &:active {
    opacity: 0.8;
  }
}

&-selected-date &-date {
  background: #3fc7fa;
  color: #fff;
  &:hover {
    background: #3fc7fa;
  }
}

&-month-select,
    &-year-select {
      width: 70px;
      float: right;
      margin-right: 5px;
    }

&-ping-left::before {
  left: 0;
  border-left: 1px solid red;
}
&-ping-right::after {
  right: 0;
  border-right: 1px solid red;
}

&-description {
  width: min-content;
  padding: 0 8px;
  border-radius: 10px;
  color: var(--adm-color-weak);
  font-size: var(--adm-font-size-main);
  background-color: var(--adm-color-fill-content);
}

&:hover {
  background: linear-gradient(135deg, var(--r-accent) 0%, color-mix(in oklab, var(--r-accent) 80%, #000) 100%);
  color: var(--r-btn-fg) !important;
  box-shadow: 0 0 0 1px var(--r-accent), 0 0 32px -4px var(--r-accent);
  transform: translateY(-1px);
}

&::before {
  content: '';
  width: 7px; height: 7px;
  border-radius: 50%;
  background: var(--r-magenta);
  box-shadow: 0 0 8px var(--r-magenta);
  animation: respawn-pulse 1.6s ease-in-out infinite;
}

&:not(.@{treePrefixCls}-show-line) {
  .@{treeNodePrefixCls} {
    .@{treePrefixCls}-switcher-noop {
      background: none;
    }
  }
}

&-treenode-disabled {
  > span:not(.@{treePrefixCls}-switcher),
  > a,
  > a span {
    color: #767676;
    cursor: not-allowed;
  }
}

&-more {
  background: rgba(255, 0, 0, 0.1);
  border: 1px solid blue;
}
&-add {
  background: rgba(0, 255, 0, 0.1);
  border: 1px solid green;
}

h1 {
  display: inline-block;
  vertical-align: middle;
  font-size: 20px;
  margin: 0 0 0 12px;
  font-family: 'Myriad Pro', 'Helvetica Neue', Arial, Helvetica, sans-serif;
  font-weight: 400;
}

&-week {
  margin-bottom: @v-spacing-large;
  margin-bottom: var(--am-calendar-week-marginTB, @v-spacing-large);
  display: flex;
  flex-direction: row;
  padding: 0 @h-spacing-large;
  padding: 0 var(--am-calendar-week-paddingLR, @h-spacing-large);
}

&.swiper-button-disabled {
	background-color: var(--theme-bg2-color, #f4f5f7);
	border-color: var(--theme-bg2-color, #f4f5f7);
	cursor: not-allowed;
}

&-subtitle {
  margin-top: @v-spacing-standard;
  margin-top: var(--am-coupon-subTitle-marginTop, @v-spacing-standard);
  font-size: @font-size-content;
  font-size: var(--am-coupon-subtitle-size, @font-size-content);
  color: @color-text-subtitle;
  color: var(--am-coupon-subtitle-color, @color-text-subtitle);
}

&-btn {
  color: @color-text-primary;
  color: var(--am-amount-btn-font-color, @color-text-primary);
  line-height: @line-height-base;
  line-height: var(--am-amount-btn-line-height, @line-height-base);
  font-size: @font-size-subtitle;
  font-size: var(--am-amount-btn-font-size, @font-size-subtitle);
}

&-4 {
	width: @size-11;
	width: var(--am-grid-icon4-size, @size-11);
	height: @size-11;
	height: var(--am-grid-icon4-size, @size-11);
	margin-bottom: @v-spacing-standard;
	margin-bottom: var(--am-grid-icon4-marginBottom, @v-spacing-standard);
}

&-title {
  line-height: @line-height-base;
  line-height: var(--am-amount-title-line-height, @line-height-base);
  color: @color-text-title;
  color: var(--am-amount-title-color, @color-text-title);
  font-size: @font-size-list;
  font-size: var(--am-amount-title-font-size, @font-size-list);
}

&-3 {
	height: @size-5;
	height: var(--am-grid-text3-height, @size-5);
	line-height: @size-5;
	line-height: var(--am-grid-text3-height, @size-5);
	font-size: @font-size-subtitle;
	font-size: var(--am-grid-text3-fontSize, @font-size-subtitle);
}

&-2 {
	height: @size-6;
	height: var(--am-grid-text2-height, @size-6);
	line-height: @size-6;
	line-height: var(--am-grid-text2-height, @size-6);
	font-size: @font-size-list;
	font-size: var(--am-grid-text2-fontSize, @font-size-list);
}

&-3 {
	width: @size-9;
	width: var(--am-grid-icon3-size, @size-9);
	height: @size-9;
	height: var(--am-grid-icon3-size, @size-9);
	margin-bottom: @v-spacing-large;
	margin-bottom: var(--am-grid-icon3-marginBottom, @v-spacing-large);
}

&-ghost-warning {
  color: @color-orange-1;
  color: var(--am-tag-ghost-warning-color, @color-orange-1);
  border: 1px solid @color-orange-1;
  border: 1px solid var(--am-tag-ghost-warning, @color-orange-1);
}

&-icon-danger {
  color: @color-tangerine-1;
  color: var(--am-tag-icon-font-danger, @color-tangerine-1);
  background: @color-tangerine-2;
  background: var(--am-tag-icon-bg-danger, @color-tangerine-2);
}

&-ghost-primary {
  color: @color-brand-1;
  color: var(--am-tag-ghost-primary-color, @color-brand-1);
  border: 1px solid @color-brand-1;
  border: 1px solid var(--am-tag-ghost-primary, @color-brand-1);
}

&-icon-warning {
  color: @color-orange-1;
  color: var(--am-tag-icon-font-warning, @color-orange-1);
  background: @color-orange-2;
  background: var(--am-tag-icon-bg-warning, @color-orange-2);
}

&-icon-primary {
  color: @color-brand-1;
  color: var(--am-tag-icon-font-primary, @color-brand-1);
  background: @color-brand-2;
  background: var(--am-tag-icon-bg-primary, @color-brand-2);
}

&-icon .a-image {
  height: @size-9;
  height: var(--am-tips-dialog-image-size, @size-9);
  width: @size-9;
  width: var(--am-tips-dialog-image-size, @size-9);
}

&-2 {
	width: @icon-size-md;
	width: var(--am-grid-icon2-size, @icon-size-md);
	height: @icon-size-md;
	height: var(--am-grid-icon2-size, @icon-size-md);
	margin-right: @h-spacing-large;
	margin-right: var(--am-grid-icon2-marginRight, @h-spacing-large);
}

#write .md-fences:not([class*=md-fences-math]):not([class*=md-diagram]) {
    color: var(--df);
    font-family: var(--v-fm-code);
    font-size: .875em;
    border-radius: var(--c-br-b);
    border: @codeblockBorderWidth solid var(--std-code-sd);
    margin: @paragraphPadding 0 0;
}

path {
  .replaceColor(#B8D7FF, fill);
  .replaceColor(#8F69FF, fill);
  .replaceColor(#6D4AFF, fill);
  .replaceColor(#FFBB93, fill);
  .replaceColor(#85D4F5, fill);
  .replaceColor(#D6F1FC, fill);
}

@font-face {
    font-family: 'argon';
    src: url('../fonts/argon.woff2') format('woff2'),
        url('../fonts/argon.woff') format('woff');
    font-weight: normal;
    font-style: normal;
    font-display: swap;
}

&::before {
  background:    url('atom://seti-ui/icons/project.svg') no-repeat;
  content:       '';
  height:        24px;
  margin-bottom: -7px;
  width:         30px;
  margin-right:  -5px;
}

0%,
  20%,
  50%,
  80%,
  100% {
    transform: translateY(-50%);
    -webkit-transform: translateY(calc(-50% - 0.5px));
  }

10%,
  30%,
  50%,
  70%,
  90% {
    -webkit-transform: translateX(-10px);
            transform: translateX(-10px);
  }

@font-face {
  font-family: 'Font Awesome 6 Brands';
  font-style: normal;
  font-weight: 400;
  font-display: @fa-font-display;
  src: url('@{fa-font-path}/fa-brands-400.woff2') format('woff2'),
    url('@{fa-font-path}/fa-brands-400.ttf') format('truetype');
}

@font-face {
  font-family: 'Font Awesome 6 Free';
  font-style: normal;
  font-weight: 400;
  font-display: @fa-font-display;
  src: url('@{fa-font-path}/fa-regular-400.woff2') format('woff2'),
    url('@{fa-font-path}/fa-regular-400.ttf') format('truetype');
}

@link-color: @primary-color;

@link-hover-color: tint(@link-color, 20%);

@link-active-color: shade(@link-color, 5%);

@link-hover-decoration: none;

@template-bg-color: #333;
@template-bg-color-light: #ECECEC;
@template-nav-bg-color: fade(@template-bg-color, 95%);
@template-text-color: #CCC;
@template-text-title-color: #BCBCBC;
@template-text-color-light: #FFF;

// Slider
@slider-color              : tint(@primary-color, 20%);
@slider-height             : 4px;
@slider-margin             : 16px 0;
@slider-button-wrap-size   : 18px;
@slider-button-wrap-offset : -4px;
@slider-disabled-color     : #ccc;

@tabs-prefix-cls: rc-tabs;

@easing-in-out: cubic-bezier(0.35, 0, 0.25, 1);

@effect-duration: 0.3s;

#top-titlebar :is(.ty-menu-btn-area-sub1, .ty-menu-btn-area-sub2, .ty-menu-btn-area-sub3),
.ty-md-radio-button-off::before,
.ion-chevron-left::before,
.ion-checkmark::before,
.fa-code::before {
    color: var(--a-c);
    vertical-align: middle;
}

path[fill="#667B99"], // dark
    path[fill="#6F839F"], // dim
    [style*="color: rgb(111, 131, 159)"], // dark
    [style*="color: rgb(111, 131, 159)"] // dim
    {
      color: @subtext1 !important;
      fill: @subtext1 !important;
    }

@zindex-navbar:            1000;
@zindex-dropdown:          1000;
@zindex-popover:           1060;
@zindex-tooltip:           1070;
@zindex-navbar-fixed:      1030;
@zindex-modal-background:  1040;
@zindex-modal:             1050;
